```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from the input buffer
    auto adaptor = hexi::buffer_adaptor(buffer);

    NetworkPacket packet;

    // Read packet_id using arithmetic deserialization
    adaptor >> packet.packet_id;

    // Read username using prefixed string deserialization
    adaptor >> packet.username;

    // Read scores count and use read_container to deserialize the vector
    uint32_t scores_count;
    adaptor >> scores_count;
    adaptor.read_container(packet.scores, scores_count);

    // Read metadata using null_terminated string deserialization
    adaptor >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    adaptor.skip(adaptor.size());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from the input buffer
    auto adaptor = hexi::buffer_adaptor(buffer);

    PacketInfo info;

    // Use span() to get zero-copy view of packet_id
    auto id_span = adaptor.span<uint32_t>(1);
    info.packet_id = *id_span.data();

    // Use prefixed adaptor to get string_view of username
    adaptor >> info.username;

    // Read scores count and skip the scores vector
    uint32_t scores_count;
    adaptor >> scores_count;
    adaptor.skip(scores_count * sizeof(uint32_t));

    return info;
}
```

