Based on the reference materials and detailed specifications, here's the complete implementation:

```cpp
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <string_view>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization: convert to little-endian and write
        adaptor.write(sensor_id);

        for (auto& temp : temperatures) {
            auto converted = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(temp);
            adaptor.write(converted);
        }

        auto converted_pressure = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(pressure);
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialization: read and then convert from little-endian to native
        adaptor.read(&sensor_id, 1);

        // Read temperatures count (assuming it's stored as uint32_t)
        uint32_t temps_count;
        adaptor.read(&temps_count, 1);
        temperatures.resize(temps_count);

        for (auto& temp : temperatures) {
            adaptor.read(&temp, 1);
            hexi::endian::little_to_native_inplace(temp);
        }

        adaptor.read(&pressure, 1);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);
    stream.serialise(data);
    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);
    MeasurementData data;
    stream.deserialise(data);
    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);
    SensorInfo info;

    // Use view to extract null-terminated sensor name
    info.sensor_name = stream.view();

    // Use enforce_read_bounds to check if there's enough data for sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    stream.read(&info.sensor_id, 1);

    // Skip remaining data
    stream.skip(buffer.size() - stream.total_read());

    return info;
}
